    53→static void test_representative_100(void)
    54→{
    55→    /* --- Section 1: Special IEEE 754 values (7) --- */
    56→    emit(0.0);
    57→    emit(-0.0);
    58→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    59→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    60→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    61→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    62→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    63→
    64→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    65→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    66→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    67→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    68→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    69→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    70→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    71→
    72→    /* --- Section 3: Normal boundary values (6) --- */
    73→    emit(DBL_MIN);                              /* smallest positive normal: 2^-1022 */
    74→    emit(-DBL_MIN);                             /* smallest negative normal */
    75→    emit_u(0x0010000000000001ULL);              /* one ULP above DBL_MIN */
    76→    emit(DBL_MAX);                              /* largest positive normal: 0x7fefffffffffffff */
    77→    emit(-DBL_MAX);                             /* largest negative normal */
    78→    emit_u(0x7fefffffffffffffULL - 1);          /* one ULP below DBL_MAX: 0x7feffffffffffffe */
    79→
    80→    /* --- Section 4: Near 1.0 - ULP density region (8) --- */
    81→    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    82→    emit(1.0);
    83→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    84→    emit_u(0x3feffffffffffffeULL);  /* a few ULPs below 1.0 */
    85→    emit_u(0x3ff0000000000010ULL);  /* a few ULPs above 1.0 */
    86→    emit(-1.0);
    87→    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    88→    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    89→
    90→    /* --- Section 5: Exponent switching points (6) --- */
    91→    emit_u(0x3fe0000000000000ULL);  /* 0.5 exactly */
    92→    emit_u(0x3fdfffffffffffffULL);  /* one ULP below 0.5 */
    93→    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    94→    emit_u(0x4000000000000000ULL);  /* 2.0 exactly */
    95→    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    96→    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
    97→
    98→    /* --- Section 6: Pure integers (12) --- */
    99→    emit(-10.0);
   100→    emit(-5.0);
   101→    emit(-3.0);
   102→    emit(-2.0);
   103→    emit(-100.0);
   104→    emit(100.0);
   105→    emit(2.0);
   106→    emit(3.0);
   107→    emit(5.0);
   108→    emit(10.0);
   109→    emit(1.0e15);   /* large integer representable exactly as double */
   110→    emit(-1.0e15);  /* large negative integer */
   111→
   112→    /* --- Section 7: Near-integer and half-integer values (12) --- */
   113→    emit(0.1);
   114→    emit(0.25);
   115→    emit(1.25);
   116→    emit(0.75);
   117→    emit(0.9);
   118→    emit(1.5);
   119→    emit(2.5);
   120→    emit(-0.1);
   121→    emit(-0.5);
   122→    emit(-0.9);
   123→    emit(-1.5);
   124→    emit(-2.5);
   125→
   126→    /* --- Section 8: Mixed fractional mid-range values (10) --- */
   127→    emit(-5.9);
   128→    emit(-5.1);
   129→    emit(-3.7);
   130→    emit(-2.2);
   131→    emit(2.2);
   132→    emit(3.7);
   133→    emit(5.1);
   134→    emit(5.9);
   135→    emit(100.375);    /* large enough integer part, exact fraction */
   136→    emit(-100.625);   /* negative counterpart */
   137→
   138→    /* --- Section 9: Large values where fractional part vanishes (10) --- */
   139→    emit(1.0e7);         /* above 2^23: float mantissa exhausted */
   140→    emit(-1.0e7);
   141→    emit(1.0e16);        /* above 2^53: double mantissa exhausted, all integer */
   142→    emit(-1.0e16);
   143→    emit(1.0e17);
   144→    emit(-1.0e17);
   145→    emit_u(0x4330000000000000ULL);  /* 2^52: exact double integer boundary */
   146→    emit_u(0x4340000000000000ULL);  /* 2^53: all doubles >= this are integers */
   147→    emit_u(0x4350000000000000ULL);  /* 2^54 */
   148→    emit_u(0xc340000000000000ULL);  /* -2^53: negative integer boundary */
   149→
   150→    /* --- Section 10: ULP neighbors of key power-of-2 transitions (23) --- */
   151→    emit_u(0x3fc0000000000000ULL);  /* 0.125 = 2^-3 */
   152→    emit_u(0x3fd8000000000000ULL);  /* 0.375 = 3*2^-3 */
   153→    emit_u(0x4060000000000000ULL);  /* 128.0 = 2^7 */
   154→    emit_u(0x4080000000000000ULL);  /* 512.0 = 2^9 */
   155→    emit_u(0x4010000000000000ULL);  /* 4.0 = 2^2 */
   156→    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0 */
   157→    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0 */
   158→    emit_u(0x4020000000000000ULL);  /* 8.0 = 2^3 */
   159→    emit_u(0x401fffffffffffffULL);  /* one ULP below 8.0 */
   160→    emit_u(0x4038000000000000ULL);  /* 24.0 */
   161→    emit_u(0x4030000000000000ULL);  /* 16.0 = 2^4 */
   162→    emit_u(0x408f400000000000ULL);  /* 1000.0 */
   163→    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 ULP: fractional part just becomes representable */
   164→    emit_u(0x432fffffffffffffULL);  /* one ULP below 2^52 */
   165→    emit_u(0x433fffffffffffffULL);  /* one ULP below 2^53 */
   166→    emit_u(0x4340000000000001ULL);  /* 2^53 + 1: integer, no fractional part */
   167→    emit_u(0xc330000000000000ULL);  /* -2^52 */
   168→    emit_u(0xc32fffffffffffffULL);  /* negative: one ULP below 2^52 magnitude */
   169→    emit_u(0x3ff921fb54442d18ULL);  /* pi/2 ~ 1.5708: has both int and frac parts */
   170→    emit_u(0x400921fb54442d18ULL);  /* pi ~ 3.1416 */
   171→    emit_u(0x4012d97c7f3321d2ULL);  /* 3pi/2 ~ 4.7124 */
   172→    emit_u(0x401921fb54442d18ULL);  /* 2pi ~ 6.2832 */
   173→    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: frac = ln2, int = 0 */
